sys_ui_action.script:
(function executeAction(current, previous) {

    // 1. Check if a Document already exists to prevent duplicate background records
    var existingDoc = new GlideRecord('dms_document');
    existingDoc.addQuery('x_enno_change_re_0_build_change', current.getUniqueValue());
    existingDoc.query();

    if (existingDoc.next()) {

        // If a document already exists for this Change, safely redirect to it
        action.setRedirectURL('dms_document.do?sys_id=' + existingDoc.getUniqueValue());

    } else {

        // 2. If no document exists, use the XML payload method to open a New form (-1)
        var url = 'dms_document.do?sys_id=-1';

        // 3. Retain current functionality: Auto-link it to the Change Request
        url += '&sysparm_query=x_enno_change_re_0_build_change=' + current.getUniqueValue();

        // 4. Redirect the user
        action.setRedirectURL(url);

        // 5. Provide a helpful system message
        gs.addInfoMessage('Please complete and save the Document for Build Change Request ' + current.getDisplayValue('number'));

    }

})(current, previous);
